def maximumBinaryString(self, binary: str) -> str:
    result = binary
    for i in range(len(binary)):
        if binary[i:i+2] == '00':
            result = max(result, '10' + result[i+2:])
        elif binary[i:i+2] == '10':
            result = max(result, '01' + result[i+2:])
    return result

